// PASO 1. Leer el input de forma flexible.
const input = $input.first().json.body || $input.first().json;
const startedAtMs = Date.now();

// PASO 2. Definir helpers simples y declarativos.
function slugify(text) {
  return String(text || 'documento')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '') || 'documento';
}

function normalize(text) {
  const replacements = {
    panza: 'abdominal',
    barriga: 'abdominal',
    estomago: 'abdominal',
    nausea: 'nauseas',
    vomitos: 'vomito',
    geriatrico: 'adulto'
  };

  const cleaned = String(text || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return cleaned ? cleaned.split(' ').map((token) => replacements[token] || token) : [];
}

function buildVector(text, dims = 64) {
  const vector = Array(dims).fill(0);

  for (const token of normalize(text)) {
    let hash = 0;
    for (let i = 0; i < token.length; i++) hash = ((hash << 5) - hash) + token.charCodeAt(i);
    vector[Math.abs(hash) % dims] += 1;
  }

  const norm = Math.sqrt(vector.reduce((acc, value) => acc + (value * value), 0)) || 1;
  return vector.map((value) => Number((value / norm).toFixed(6)));
}

function splitIntoSections(text) {
  const clean = String(text || '').replace(/\r/g, '').trim();
  if (!clean) return [];

  const blocks = clean.split(/\n\s*\n+/).map((block) => block.trim()).filter(Boolean);
  return blocks.map((block, index) => ({
    slug: `bloque-${index + 1}`,
    title: `Bloque ${index + 1}`,
    text: block
  }));
}

function chunkSections(sections, doc) {
  const chunks = [];

  for (const [sectionIndex, section] of sections.entries()) {
    const sentences = String(section.text || '')
      .split(/(?<=[.!?])\s+/)
      .map((sentence) => sentence.trim())
      .filter(Boolean);

    const effectiveSentences = sentences.length ? sentences : [String(section.text || '').trim()].filter(Boolean);
    let buffer = [];
    let counter = 0;

    const flush = () => {
      const text = buffer.join(' ').trim();
      if (!text) return;
      counter += 1;
      chunks.push({
        chunkId: `${doc.docId}-${section.slug || ('sec' + (sectionIndex + 1))}-c${counter}`,
        docId: doc.docId,
        title: doc.title,
        category: doc.category,
        version: doc.version,
        section: section.title,
        sectionSlug: section.slug,
        text,
        tags: doc.tags,
        sourceLabel: `${doc.title} / ${section.title}`
      });
      buffer = [];
    };

    for (const sentence of effectiveSentences) {
      const current = buffer.join(' ');
      if (current && (current.length + sentence.length + 1) > 320) flush();
      buffer.push(sentence);
    }

    flush();
  }

  return chunks;
}

// PASO 3. Transformar texto libre en un documento estructurado.
const sourceText = input.anonymizedMarkdown || input.markdown || input.anonymizedText || input.originalText || input.text || '';
const sections = Array.isArray(input.documents?.[0]?.sections)
  ? input.documents[0].sections
  : splitIntoSections(sourceText);

const valid = sections.length > 0;
if (!valid) {
  return [{
    json: {
      success: false,
      valid: false,
      error: 'Se requiere markdown, text o documents[].sections[]'
    }
  }];
}

const document = {
  docId: input.docId || slugify(input.documentTitle || input.title || 'documento-clinico'),
  title: input.documentTitle || input.title || 'Documento clinico parseado',
  category: input.category || 'prospecto',
  version: input.version || new Date().toISOString().slice(0, 10),
  tags: Array.isArray(input.tags) ? input.tags : ['parseado', 'clinico'],
  sections
};

// PASO 4. Crear chunks semanticos.
const chunks = chunkSections(document.sections, document);

// PASO 5. Crear embeddings simulados para cada chunk.
const embeddedChunks = chunks.map((chunk) => {
  const textForEmbedding = [chunk.title, chunk.section, ...(chunk.tags || []), chunk.text].join(' ');
  return {
    ...chunk,
    textForEmbedding,
    vector: buildVector(textForEmbedding)
  };
});

return [{
  json: {
    success: true,
    valid: true,
    documents: [document],
    chunks,
    embeddedChunks,
    ingestion: {
      strategy: 'semantico-por-secciones',
      overlap: 0,
      chunkCount: chunks.length,
      embeddedCount: embeddedChunks.length,
      latencyMs: Math.max(Date.now() - startedAtMs, 0)
    },
    contractOut: {
      step: '09-ingesta-rag-sin-vector-db',
      next: '10-rag-consulta-sin-vector-db',
      expectsNext: '{question, embeddedChunks[], patientContext?, topK?}'
    }
  }
}];
